  // ... orchestration ...

  for (let i = 0; i < rows.length; i++) {

    if (hasTimePassed_(300000)) { ... }

    const name = String(row[12]).toLowerCase().replace(/[^a-zก-๙]/g, '');

    const score = levenshtein(name, candidate) / Math.max(name.length, candidate.length);

